import{_ as a,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"6. Definitions","description":"","frontmatter":{"title":"6. Definitions","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/preliminary/6-definitions.md","filePath":"ebas/has-managers-admin/common-terms/preliminary/6-definitions.md"}'),r={name:"ebas/has-managers-admin/common-terms/preliminary/6-definitions.md"};function o(i,e,l,p,d,c){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_6-definitions" tabindex="-1">6. Definitions <a class="header-anchor" href="#_6-definitions" aria-label="Permalink to &quot;6. Definitions&quot;">​</a></h1><p><strong>6.1</strong> In this Section 1:</p><p><strong>(a)</strong> Act means the Fair Work Act 2009 (Cth).</p><p><strong>(b)</strong> Adoption includes the placement of a child under a permanent care order.</p><p><strong>(c)</strong> Agreement means the Victorian Public Health Sector (Health and Allied Services, Managers and Administrative Workers) Single Interest Enterprise Agreement 2020-2024.</p><p><strong>(d)</strong> AIC means the applicable agreement implementation committee continuing or established under 70.10.</p><p><strong>(e)</strong> Base rate of pay means the rate of pay payable to an Employee in accordance with <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a> and <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a> for his or her ordinary hours of work, but not including any incentive-based payments and bonuses, loadings, allowances, overtime, penalty rates or any other separately identifiable amounts.</p><p><strong>(f)</strong> Commission means the Fair Work Commission or any successor body.</p><p><strong>(g)</strong> De facto partner, in relation to an Employee, means: a person who, although not married to the Employee, lives with them in a relationship as a couple on a genuine domestic basis (whether the Employee and the person are of the same sex or different sexes); and includes a former de facto of the Employee.</p><p><strong>(h)</strong> Dental Assistant means an Employee classified in accordance with Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/2d-classification-structure-health-allied-services.html">Schedule 2D</a> of this Agreement, and paid pursuant to Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p><p><strong>(i)</strong> Department Head means a person responsible for a department or section of the hospital or health service covered by this Agreement.</p><p><strong>(j)</strong> Department refers to Employees within a department who are covered by this Agreement.</p><p><strong>(k)</strong> Designated Work Group means a group of Employees within a workplace that are entitled to elect an HSR in accordance with the OHS Act.</p><p><strong>(l)</strong> DH means the Department of Health</p><p><strong>(m)</strong> DHSV means Dental Health Services Victoria.</p><p><strong>(n)</strong> Divisional Director means a person appointed as such by the Employer.</p><p><strong>(o)</strong> Employee means a person employed by an Employer listed in <a href="/eba/ebas/has-managers-admin/schedules/1a-employers-covered.html">Schedule 1A</a> of this Section 1 who is employed in any of the classifications set out in this Agreement, other than:</p><p><strong>(i)</strong> employees employed solely or predominantly in the provision of public mental health services; and</p><p><strong>(ii)</strong> Employees employed pursuant to Health Executive Employment and Remuneration Policy</p><p><strong>(p)</strong> Employer means each organisation listed in <a href="/eba/ebas/has-managers-admin/schedules/1a-employers-covered.html">Schedule 1A</a>.</p><p><strong>(q)</strong> Employer Organisation means an organisation of Employers, which would specifically include the VHIA.</p><p><strong>(r)</strong> FFPPOA means first full pay period on or after.</p><p><strong>(s)</strong> Health and Allied Services Employee means an Employee classified in accordance with Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/2d-classification-structure-health-allied-services.html">Schedule 2D</a> of this Agreement, and paid pursuant to Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p><p><strong>(t)</strong> HSR means an Employee elected to the position of Occupational Health and Safety Representative of a Designated Work Group in accordance with the OHS Act.</p><p><strong>(u)</strong> HWU Delegate has the same meaning as HWU Representative or Job Representative.</p><p><strong>(v)</strong> HWU or Union means Health Services Union Victoria No 1 Branch, trading as the “Health Workers Union”.</p><p><strong>(w)</strong> Immediate family means a spouse, former spouse, de facto partner, former de facto partner, child including adopted child, step child and ex-nuptial child, parent, grandparent, grandchild or sibling of the Employee; and a child, step child and ex-nuptial child, parent grandparent, grandchild or sibling of a spouse or de facto partner of the Employee.</p><p><strong>(x)</strong> Manager and Administrative Worker means an Employee classified in accordance with Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a> or Part 2 of</p><p><strong>(y)</strong> Medical certificate means a certificate from a medical practitioner.</p><p><strong>(z)</strong> Medical practitioner means a person registered as a medical practitioner by the Medical Board of Australia.</p><p><strong>(aa)</strong> Modern Award means the Health Professionals and Support Services Award 2020.</p><p><strong>(bb)</strong> National Employment Standards or NES means Part 2-2 of the Act as amended from time to time.</p><p><strong>(cc)</strong> not employed by Royal Women’s Hospital or Royal Children’s Hospital means classified under Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a>.</p><p><strong>(dd)</strong> OHS Act means the Occupational Health and Safety Act 2004 (Vic) as varied from time to time, or any successor to that Act.</p><p><strong>(ee)</strong> Party means the Employer, Employees and the HWU who are covered by this Agreement.</p><p><strong>(ff)</strong> School age, in relation to a child, means the age at which the child is required by law to attend school.</p><p><strong>(gg)</strong> Spouse includes a former spouse.</p><p><strong>(hh)</strong> VHIA means the Victorian Hospitals’ Industrial Association.</p><p><strong>(ii)</strong> WIRC Act means the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic), or if applicable in the particular situation the Accident Compensation Act 1985 (Vic) or the Workers Compensation Act 1958 (Vic).</p><p><strong>(jj)</strong> Previous Agreement shall mean the Victorian Public Health Sector (Health and Allied Services, Managers and Administrative Workers) Single Interest Enterprise Agreement 2016-2020.</p>',40)])])}const g=a(r,[["render",o]]);export{h as __pageData,g as default};
